"use client";
import Link from "next/link";
import { useState } from "react";

const links = [["Quem Somos","/quem-somos"],["Nossas Lojas","/lojas"],["Delivery","/delivery"],["Drogaria","/drogaria"],["Revista","/revista"]];
export function Header() {
  const [open,setOpen]=useState(false);
  return <header className="site-header"><div className="shell header-inner">
    <Link href="/" className="brand" aria-label="Coopercica página inicial"><span className="brand-mark">C</span><span>COOPERCICA</span></Link>
    <button className="menu-button" onClick={()=>setOpen(!open)} aria-expanded={open}>Menu</button>
    <nav className={open?"nav open":"nav"}>{links.map(([label,href])=><Link key={href} href={href} onClick={()=>setOpen(false)}>{label}</Link>)}<a className="nav-cta" href="https://www.coopercicadelivery.com.br/">Comprar online ↗</a></nav>
  </div></header>;
}
